function banAddress(
    address _addr,
    bool _ban
)
    external
    onlyFromOwnerOrNamed("bridge_watchdog")
    nonReentrant
{
    if (addressBanned[_addr] == _ban) revert B_INVALID_STATUS();
    addressBanned[_addr] = _ban;
    emit AddressBanned(_addr, _ban);
}
